<?php
$pageTitle='Field Dispatch';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('field_dispatch');
$pdo=getDB();
$techs=$pdo->query('SELECT id,email,first_name,last_name FROM '.table('users').' WHERE status="active" AND can_login_erp=1 ORDER BY first_name,email')->fetchAll();
$jobs=$pdo->query('SELECT id,job_card_number,customer_name,customer_phone,status,plate_number,vin FROM '.table('job_cards').' WHERE status IN ("draft","diagnosis","in_progress","waiting_parts","scheduled") ORDER BY created_at DESC LIMIT 300')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){
  try{
    $action=(string)($_POST['action']??'');
    if($action==='dispatch'){
      createFieldDispatch($pdo,(int)$_POST['job_card_id'],(int)$_POST['technician_user_id'],trim((string)$_POST['dispatch_date']),trim((string)$_POST['start_time']),trim((string)$_POST['service_address']));
      flash('success','Field dispatch created.');
    }elseif($action==='status'){
      $status=trim((string)$_POST['dispatch_status']);
      $fields=['accepted'=>'accepted_at','enroute'=>'enroute_at','arrived'=>'arrived_at','completed'=>'completed_at'];
      $sql='UPDATE '.table('field_service_dispatches').' SET dispatch_status=?';
      if(isset($fields[$status])){$sql.=','.$fields[$status].'=NOW()';}
      $sql.=' WHERE id=?';
      $pdo->prepare($sql)->execute([$status,(int)$_POST['id']]);
      flash('success','Dispatch status updated.');
    }elseif($action==='route'){
      $number=nextScopedDocumentNumber($pdo,'field_route',setting('field_route_prefix','ROUTE'),operationalScope($pdo));
      $pdo->prepare('INSERT INTO '.table('field_service_routes').' (route_number,technician_user_id,route_date,route_name,start_location,end_location,status,notes) VALUES (?,?,?,?,?,?, "planned", ?)')->execute([$number,(int)$_POST['technician_user_id'],trim((string)$_POST['route_date']),trim((string)$_POST['route_name']),trim((string)$_POST['start_location']),trim((string)$_POST['end_location']),trim((string)$_POST['notes'])]);
      flash('success','Route created.');
    }elseif($action==='route_stop'){
      $pdo->prepare('INSERT INTO '.table('field_service_route_stops').' (field_service_route_id,job_card_id,field_service_dispatch_id,stop_order,eta,status,notes) VALUES (?,?,?,?,?,"planned",?)')->execute([(int)$_POST['route_id'],(int)$_POST['job_card_id'],(int)($_POST['dispatch_id']??0)?:null,(int)$_POST['stop_order'],trim((string)$_POST['eta'])?:null,trim((string)$_POST['notes'])]);
      flash('success','Route stop added.');
    }
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'field-dispatch']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/field-dispatch.php');
}
$dispatches=$pdo->query('SELECT d.*,jc.job_card_number,jc.customer_name,jc.plate_number,u.email technician_email FROM '.table('field_service_dispatches').' d LEFT JOIN '.table('job_cards').' jc ON jc.id=d.job_card_id LEFT JOIN '.table('users').' u ON u.id=d.technician_user_id ORDER BY d.dispatch_date DESC,d.created_at DESC LIMIT 250')->fetchAll();
$routes=$pdo->query('SELECT r.*,u.email technician_email,(SELECT COUNT(*) FROM '.table('field_service_route_stops').' s WHERE s.field_service_route_id=r.id) stop_count FROM '.table('field_service_routes').' r LEFT JOIN '.table('users').' u ON u.id=r.technician_user_id ORDER BY r.route_date DESC,r.created_at DESC LIMIT 80')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Field Service Control</div><h2 class="h4 mb-1">Field Dispatch</h2><p class="text-secondary mb-0">Assign technicians, schedule visits, control route plans, and track mobile job status.</p></div><a class="btn btn-outline-primary" href="<?php echo esc(ADMIN_URL); ?>/erp/technician-mobile.php"><?php echo t('Technician Mobile', 'موبايل الفني'); ?></a></div>
<div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4 mb-4"><input type="hidden" name="action" value="dispatch"><h2 class="h5 mb-3">Create Dispatch</h2><label class="form-label">Job Card</label><select class="form-select mb-2" name="job_card_id"><?php foreach($jobs as $job): ?><option value="<?php echo (int)$job['id']; ?>"><?php echo esc($job['job_card_number'].' · '.$job['customer_name'].' · '.$job['plate_number']); ?></option><?php endforeach; ?></select><label class="form-label">Technician</label><select class="form-select mb-2" name="technician_user_id"><?php foreach($techs as $tech): ?><option value="<?php echo (int)$tech['id']; ?>"><?php echo esc(trim(($tech['first_name']??'').' '.($tech['last_name']??'')).' · '.$tech['email']); ?></option><?php endforeach; ?></select><div class="row g-2"><div class="col-6"><label class="form-label">Date</label><input class="form-control" type="date" name="dispatch_date" value="<?php echo esc(date('Y-m-d')); ?>"></div><div class="col-6"><label class="form-label">Start</label><input class="form-control" type="time" name="start_time"></div></div><label class="form-label mt-2">Service Address</label><textarea class="form-control mb-3" name="service_address" rows="3"></textarea><button class="btn btn-brand w-100">Create Dispatch</button></form><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="route"><h2 class="h5 mb-3">Create Route</h2><select class="form-select mb-2" name="technician_user_id"><?php foreach($techs as $tech): ?><option value="<?php echo (int)$tech['id']; ?>"><?php echo esc($tech['email']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" type="date" name="route_date" value="<?php echo esc(date('Y-m-d')); ?>"><input class="form-control mb-2" name="route_name" placeholder="Route name"><input class="form-control mb-2" name="start_location" placeholder="Start location"><input class="form-control mb-2" name="end_location" placeholder="End location"><textarea class="form-control mb-3" name="notes" rows="2"></textarea><button class="btn btn-outline-primary w-100">Create Route</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Dispatch Board</h2><table class="table align-middle"><thead><tr><th>Dispatch</th><th>Job</th><th>Technician</th><th>Schedule</th><th>Status</th><th>Update</th></tr></thead><tbody><?php foreach($dispatches as $d): ?><tr><td><strong><?php echo esc($d['dispatch_number']); ?></strong><div class="small text-secondary"><?php echo esc($d['customer_name']); ?></div></td><td><?php echo esc($d['job_card_number'].' · '.$d['plate_number']); ?></td><td><?php echo esc($d['technician_email']); ?></td><td><?php echo esc($d['dispatch_date'].' '.$d['start_time']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($d['dispatch_status'])); ?>"><?php echo esc($d['dispatch_status']); ?></span></td><td><form method="post" class="d-flex gap-1"><input type="hidden" name="action" value="status"><input type="hidden" name="id" value="<?php echo (int)$d['id']; ?>"><select class="form-select form-select-sm" name="dispatch_status"><option>accepted</option><option>enroute</option><option>arrived</option><option>completed</option><option>cancelled</option></select><button class="btn btn-sm btn-success">Save</button></form></td></tr><?php endforeach; ?><?php if(!$dispatches): ?><tr><td colspan="6" class="text-secondary">No dispatches yet.</td></tr><?php endif; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Routes</h2><table class="table"><thead><tr><th>Route</th><th>Technician</th><th>Date</th><th>Stops</th><th>Status</th></tr></thead><tbody><?php foreach($routes as $r): ?><tr><td><strong><?php echo esc($r['route_number']); ?></strong><div class="small text-secondary"><?php echo esc($r['route_name']); ?></div></td><td><?php echo esc($r['technician_email']); ?></td><td><?php echo esc($r['route_date']); ?></td><td><?php echo (int)$r['stop_count']; ?></td><td><span class="badge bg-<?php echo esc(statusTone($r['status'])); ?>"><?php echo esc($r['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>